import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,o as s,r as c,s as l,t as u}from"./chunks/javap.CpTN0-Ru.js";const d=JSON.parse(`{"title":"Tips and Tricks for VS Code","description":"Useful tips and tricks to make your work easier.","frontmatter":{"title":"Tips and Tricks for VS Code","description":"Useful tips and tricks to make your work easier.","authors":["dicedpixels"],"prev":{"text":"Generating Sources in VS Code","link":"./generating-sources"},"next":false,"files":[]},"headers":[],"relativePath":"1.21.8/develop/getting-started/vscode/tips-and-tricks.md","filePath":"versions/1.21.8/develop/getting-started/vscode/tips-and-tricks.md","lastUpdated":1773411667000}`);var f={name:`1.21.8/develop/getting-started/vscode/tips-and-tricks.md`};function p(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Tips and Tricks for VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Tips and Tricks for VS Code”">​</a></h1><p>It&#39;s important to learn how to traverse the generate sources so that you can debug and get an understanding of the inner workings of Minecraft. Here we outline some common IDE usages.</p><h2 id="searching-for-a-minecraft-class" tabindex="-1">Searching for a Minecraft Class <a class="header-anchor" href="#searching-for-a-minecraft-class" aria-label="Permalink to “Searching for a Minecraft Class”">​</a></h2><p>Once sources are generated. it should be possible for you to search or view Minecraft classes.</p><h3 id="viewing-class-definitions" tabindex="-1">Viewing Class Definitions <a class="header-anchor" href="#viewing-class-definitions" aria-label="Permalink to “Viewing Class Definitions”">​</a></h3><p><strong>Quick Open</strong> (<kbd>Ctrl</kbd>+<kbd>P</kbd>): Type <code>#</code> followed by the class name (e.g. <code>#ResourceLocation</code>).</p><p><img src="/assets/develop/getting-started/vscode/quick-open.png" alt="Quick Open" loading="lazy"></p><p><strong>Go to Definition</strong> (<kbd>F12</kbd>): From source code, navigate to a class definition by <kbd>Ctrl</kbd> + clicking on its name, or by right-clicking it and selecting &quot;Go to Definition&quot;.</p><p><img src="/assets/develop/getting-started/vscode/go-to-definition.png" alt="Go to Definition" loading="lazy"></p><h3 id="finding-references" tabindex="-1">Finding References <a class="header-anchor" href="#finding-references" aria-label="Permalink to “Finding References”">​</a></h3><p>You can find all usages of a class by right-clicking on a class name and clicking <strong>Find All References</strong>.</p><p><img src="/assets/develop/getting-started/vscode/find-all-references.png" alt="Find All References" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>If the functions above do not work as expected, it&#39;s likely that sources are not attached properly. This can generally be fixed by cleaning up the workspace cache.</p><ul><li>Click the <strong>Show Java Status Menu</strong> button in the status bar.</li></ul><p><img src="/assets/develop/getting-started/vscode/java-ready.png" alt="Show Java Status" loading="lazy"></p><ul><li>In the menu that just opened, click <strong>Clean Workspace Cache...</strong> and confirm the operation.</li></ul><p><img src="/assets/develop/getting-started/vscode/clear-workspace.png" alt="Clear Workspace" loading="lazy"></p><ul><li>Close and reopen the project.</li></ul></div><h2 id="viewing-bytecode" tabindex="-1">Viewing Bytecode <a class="header-anchor" href="#viewing-bytecode" aria-label="Permalink to “Viewing Bytecode”">​</a></h2><p>Viewing bytecode is necessary when writing mixins. However, Visual Studio Code lacks native support for bytecode viewing, and the few extensions which add it might not work.</p><p>In such case, you can use Java&#39;s inbuilt <code>javap</code> to view bytecode.</p><ul><li><p><strong>Locate the path to Minecraft JAR:</strong></p><p>Open the Explorer view, expand the <strong>Java Projects</strong> section. Expand the <strong>Reference Libraries</strong> node in the project tree and locate a JAR with <code>minecraft-</code> in its name. Right-click on the JAR and copy the full path.</p><p>It might look something like this:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span></span></code></pre></div></li></ul><p><img src="/assets/develop/getting-started/vscode/copy-path.png" alt="Copy Path" loading="lazy"></p><ul><li><p><strong>Run <code>javap</code>:</strong></p><p>You can then run <code>javap</code> by providing the above path as the <code>cp</code> (class path) and the fully qualified class name as the final argument.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">javap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -private</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.minecraft.util.ResourceLocation</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This will print the bytecode in your terminal output.</p></li></ul><p><img src="/assets/develop/getting-started/vscode/javap.png" alt="javap" loading="lazy"></p>`,20)]])}var m=r(f,[[`render`,p]]);export{d as __pageData,m as default};